import{_ as i,o as t,c as o,ag as r}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Time Registration","description":"","frontmatter":{},"headers":[],"relativePath":"features/time-registration.md","filePath":"features/time-registration.md"}'),l={name:"features/time-registration.md"};function a(n,e,s,c,g,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="time-registration" tabindex="-1">Time Registration <a class="header-anchor" href="#time-registration" aria-label="Permalink to &quot;Time Registration&quot;">​</a></h1><p>Log working hours against projects and customers to track billable time and generate invoices from time entries.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Time registration helps you:</p><ul><li>Track how many hours you spend on each project</li><li>Calculate billable vs. non-billable time</li><li>Generate invoices directly from logged hours</li><li>Understand your effective hourly rate</li></ul><h2 id="logging-time" tabindex="-1">Logging time <a class="header-anchor" href="#logging-time" aria-label="Permalink to &quot;Logging time&quot;">​</a></h2><h3 id="create-a-time-entry" tabindex="-1">Create a time entry <a class="header-anchor" href="#create-a-time-entry" aria-label="Permalink to &quot;Create a time entry&quot;">​</a></h3><ol><li>Go to <strong>Time Registration</strong></li><li>Click <strong>Add Entry</strong> (or the + button on mobile)</li><li>Fill in: <ul><li><strong>Date</strong> — When the work was done</li><li><strong>Hours</strong> — Duration of work</li><li><strong>Project</strong> — Which project the time is for</li><li><strong>Customer</strong> — The client (auto-filled from project)</li><li><strong>Description</strong> — What you worked on</li><li><strong>Billable</strong> — Whether this time should be invoiced</li><li><strong>Hourly rate</strong> — Your rate for this work</li></ul></li><li>Click <strong>Save</strong></li></ol><h3 id="hours-only-mode" tabindex="-1">Hours-only mode <a class="header-anchor" href="#hours-only-mode" aria-label="Permalink to &quot;Hours-only mode&quot;">​</a></h3><p>For simplified time tracking, enable hours-only mode in settings. This hides the hourly rate and billable fields, showing only hours and description.</p><h2 id="invoicing-time-entries" tabindex="-1">Invoicing time entries <a class="header-anchor" href="#invoicing-time-entries" aria-label="Permalink to &quot;Invoicing time entries&quot;">​</a></h2><p>Convert logged hours into invoices:</p><ol><li>Filter time entries by customer or project</li><li>Select the entries you want to invoice</li><li>Click <strong>Create Invoice</strong></li><li>A new invoice is pre-filled with line items from the selected time entries</li><li>Review and send</li></ol><h3 id="auto-invoice-settings" tabindex="-1">Auto-invoice settings <a class="header-anchor" href="#auto-invoice-settings" aria-label="Permalink to &quot;Auto-invoice settings&quot;">​</a></h3><p>Configure automatic invoicing for time entries:</p><ol><li>Go to time registration settings</li><li>Set up auto-invoice rules</li><li>Time entries matching the rules are automatically added to invoices</li></ol><h2 id="filtering" tabindex="-1">Filtering <a class="header-anchor" href="#filtering" aria-label="Permalink to &quot;Filtering&quot;">​</a></h2><p>Filter your time entries by:</p><ul><li><strong>Customer</strong> — See time per client</li><li><strong>Project</strong> — See time per project</li><li><strong>Date range</strong> — Specific period</li><li><strong>Billable status</strong> — Billable vs. non-billable</li><li><strong>Invoice status</strong> — Invoiced vs. uninvoiced</li></ul><h2 id="bulk-actions" tabindex="-1">Bulk actions <a class="header-anchor" href="#bulk-actions" aria-label="Permalink to &quot;Bulk actions&quot;">​</a></h2><ul><li><strong>Mark as billable</strong> — Set multiple entries as billable</li><li><strong>Create invoice</strong> — Invoice multiple entries at once</li><li><strong>Archive</strong> — Move entries to archive</li><li><strong>Delete</strong> — Remove entries</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Log time daily for accurate records</li><li>Use the project filter to see per-project time totals</li><li>Check uninvoiced time regularly to avoid missing billable hours</li><li>The project-based dashboard profile highlights time tracking metrics</li></ul>',23)])])}const d=i(l,[["render",a]]);export{m as __pageData,d as default};
